+//! Test: Oracle Prefetch - Predictive Expert Loading
+//!
+//! This test demonstrates hiding SSD latency behind draft model compute:
+//! 1. Run a batch to establish "last used experts"
+//! 2. Simulate prefetching while "drafting" would occur
+//! 3. Run next batch - measure if prefetch provides speedup
+//!
+//! The key insight:
+//! - Draft model runs 300ms on CPU
+//! - SSD load takes 266ms for 2 experts
+//! - If we prefetch during drafting, SSD latency = 0ms
+//!
+//! Usage:
+//!   zig build test-oracle-prefetch -- <model.gguf>
+
+const std = @import("std");
+const moe_metal = @import("moe_metal.zig");
+const moe = @import("moe.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+pub fn main() !void {
